import{_ as r,o as a,c as i,a2 as t}from"./chunks/framework.N6Nd-M9-.js";const x=JSON.parse('{"title":"鼓励","description":"","frontmatter":{},"headers":[],"relativePath":"notes/企业文化/组长手册/04-鼓励.md","filePath":"notes/企业文化/组长手册/04-鼓励.md"}'),o={name:"notes/企业文化/组长手册/04-鼓励.md"};function d(p,e,n,l,s,g){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="鼓励" tabindex="-1">鼓励 <a class="header-anchor" href="#鼓励" aria-label="Permalink to &quot;鼓励&quot;">​</a></h1><blockquote><p>同创主悦是一条通往美好生活的道路，这条路上充满鲜花和掌声，同时也会有挫折、问题、负面情绪。作为已经走过这条路的前辈，更知道如何激励正在经历失败、低谷的队员；以切身经验体会告知队员遇到负面、处于瓶颈期时应该具有的思想、应该做出的行动，让队员明白：遇到困难要思考3个问题：你可以做什么——你能做的；要做什么——你想做的；该做什么——属于你责任范围内的。</p></blockquote><hr><h2 id="一、针对不同阶段的队员" tabindex="-1">一、针对不同阶段的队员 <a class="header-anchor" href="#一、针对不同阶段的队员" aria-label="Permalink to &quot;一、针对不同阶段的队员&quot;">​</a></h2><p style="margin:15px 0;font-size:14px;color:#666;">鼓励内容、方式、目的有所区分：</p><div style="background:linear-gradient(135deg,rgba(102,126,234,0.1) 0%,rgba(118,75,162,0.1) 100%);border:2px solid rgba(102,126,234,0.2);border-radius:16px;padding:25px;margin:20px 0;"><div style="display:flex;align-items:center;gap:10px;margin-bottom:20px;"><span style="font-size:24px;">🌱</span><span style="font-size:20px;font-weight:bold;color:#667eea;">一周</span></div><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:15px;"><div style="background:rgba(255,255,255,0.6);border-radius:12px;padding:18px;"><p style="margin:0 0 10px 0;font-size:14px;font-weight:bold;color:#667eea;">💭 思想观念</p><p style="margin:0;font-size:13px;color:#333;line-height:1.7;"> a. 讲述你选择此工作的原因<br> b. 以作业过程中遇到的各种状况来支持你向他推广的一切，包括系统、文化、公司前景 </p></div><div style="background:rgba(255,255,255,0.6);border-radius:12px;padding:18px;"><p style="margin:0 0 10px 0;font-size:14px;font-weight:bold;color:#22c55e;">📈 销售能力</p><p style="margin:0;font-size:13px;color:#333;line-height:1.7;"><strong>你做他看：</strong>把握在你成交时他最兴奋的时机点，鼓励他实践<br><br><strong>他做你看：</strong><br> · 如果成交——把握他信心最强又兴奋的时机点，肯定并鼓励再接再厉<br> · 如果未成交——鼓励他你也曾是新手，你是如何适应过来 </p></div><div style="background:rgba(255,255,255,0.6);border-radius:12px;padding:18px;"><p style="margin:0 0 10px 0;font-size:14px;font-weight:bold;color:#f59e0b;">✨ 理想效果</p><p style="margin:0;font-size:13px;color:#333;line-height:1.7;"> · 建立他的信心及对成功的渴望<br> · 了解按照系统作业的重要性和必要性<br> · 为负面做准备：被拒绝很正常，保持平常心，人数问多定会成交 </p></div></div></div><div style="background:linear-gradient(135deg,rgba(245,158,11,0.1) 0%,rgba(217,119,6,0.1) 100%);border:2px solid rgba(245,158,11,0.2);border-radius:16px;padding:25px;margin:20px 0;"><div style="display:flex;align-items:center;gap:10px;margin-bottom:20px;"><span style="font-size:24px;">🌳</span><span style="font-size:20px;font-weight:bold;color:#f59e0b;">一段时间</span></div><div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:15px;"><div style="background:rgba(255,255,255,0.6);border-radius:12px;padding:18px;"><p style="margin:0 0 10px 0;font-size:14px;font-weight:bold;color:#667eea;">💭 思想观念</p><p style="margin:0;font-size:13px;color:#333;line-height:1.7;"> a. 提醒他进入公司的初衷<br> b. 带他证明按照系统作业的重要性和必要性 </p></div><div style="background:rgba(255,255,255,0.6);border-radius:12px;padding:18px;"><p style="margin:0 0 10px 0;font-size:14px;font-weight:bold;color:#22c55e;">📈 销售能力</p><p style="margin:0;font-size:13px;color:#333;line-height:1.7;"> a. 鼓励其保持耐心、专心、信心、决心、用心<br> b. 带他一起完成目标 </p></div><div style="background:rgba(255,255,255,0.6);border-radius:12px;padding:18px;"><p style="margin:0 0 10px 0;font-size:14px;font-weight:bold;color:#f59e0b;">✨ 理想效果</p><p style="margin:0;font-size:13px;color:#333;line-height:1.7;"> · 改变他的工作习惯<br> · 建立重新开始的信心 </p></div></div></div><hr><h2 id="二、-一分钟激励-方式" tabindex="-1">二、&quot;一分钟激励&quot;方式 <a class="header-anchor" href="#二、-一分钟激励-方式" aria-label="Permalink to &quot;二、&quot;一分钟激励&quot;方式&quot;">​</a></h2><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);padding:25px;border-radius:16px;margin:20px 0;"><div style="display:flex;flex-wrap:wrap;gap:12px;justify-content:center;margin-bottom:20px;"><span style="background:linear-gradient(135deg,rgba(102,126,234,0.15) 0%,rgba(118,75,162,0.15) 100%);padding:12px 20px;border-radius:25px;font-size:14px;color:#667eea;font-weight:bold;">📢 高亢的声调</span><span style="background:linear-gradient(135deg,rgba(34,197,94,0.15) 0%,rgba(22,163,74,0.15) 100%);padding:12px 20px;border-radius:25px;font-size:14px;color:#22c55e;font-weight:bold;">💪 冲动夸张的肢体动作</span><span style="background:linear-gradient(135deg,rgba(245,158,11,0.15) 0%,rgba(217,119,6,0.15) 100%);padding:12px 20px;border-radius:25px;font-size:14px;color:#f59e0b;font-weight:bold;">🎯 明确点出值得鼓励的事情</span></div><blockquote style="margin:0;padding:15px 20px;background:rgba(102,126,234,0.08);border-left:4px solid #667eea;border-radius:0 8px 8px 0;font-size:14px;color:#333;"> 你是成败的关键，要表现出你的信心、风格以及处理问题的能力。领导能力与年纪没有绝对的关系，别紧张，只要按部就班做好你每天该做的事情。 </blockquote></div><hr><h2 id="三、运用的时机点" tabindex="-1">三、运用的时机点 <a class="header-anchor" href="#三、运用的时机点" aria-label="Permalink to &quot;三、运用的时机点&quot;">​</a></h2><div style="display:grid;grid-template-columns:repeat(3,1fr);gap:15px;margin:20px 0;"><div style="background:linear-gradient(135deg,rgba(239,68,68,0.1) 0%,rgba(220,38,38,0.1) 100%);border:2px solid rgba(239,68,68,0.2);padding:25px;border-radius:16px;text-align:center;"><p style="font-size:36px;margin:0 0 12px 0;">😔</p><p style="font-size:15px;font-weight:bold;margin:0;color:#ef4444;">A. 做不好的时候</p></div><div style="background:linear-gradient(135deg,rgba(34,197,94,0.1) 0%,rgba(22,163,74,0.1) 100%);border:2px solid rgba(34,197,94,0.2);padding:25px;border-radius:16px;text-align:center;"><p style="font-size:36px;margin:0 0 12px 0;">🎉</p><p style="font-size:15px;font-weight:bold;margin:0;color:#22c55e;">B. 做得好的时候</p></div><div style="background:linear-gradient(135deg,rgba(245,158,11,0.1) 0%,rgba(217,119,6,0.1) 100%);border:2px solid rgba(245,158,11,0.2);padding:25px;border-radius:16px;text-align:center;"><p style="font-size:36px;margin:0 0 12px 0;">🔋</p><p style="font-size:15px;font-weight:bold;margin:0;color:#f59e0b;">C. 感觉没有JUICE的时候</p></div></div><hr><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><div style="background:linear-gradient(135deg,#667eea 0%,#764ba2 100%);padding:30px;border-radius:16px;margin:20px 0;text-align:center;box-shadow:0 8px 25px rgba(102,126,234,0.3);"><p style="margin:0;font-size:18px;font-weight:bold;color:#fff;line-height:2;letter-spacing:1px;"> 建设他的信心，让他渴望得到我们的机会并觉得他可以做得到，<br> 让他知道我们对他的期待，并乐意协助他一起共创事业！ </p></div>',16)])])}const c=r(o,[["render",d]]);export{x as __pageData,c as default};
